(function () {
  function renderNode(node) {
    if (!node || node.getAttribute("data-obsite-math-ready") === "true") {
      return;
    }

    var raw = node.textContent || "";
    if (!String(raw).replace(/\s+/g, "")) {
      return;
    }

    var displayMode = node.classList && node.classList.contains("math-display");
    var katex = typeof window !== "undefined" ? window.katex : null;
    node.setAttribute("data-obsite-math-ready", "true");

    if (katex && typeof katex.render === "function") {
      katex.render(raw, node, { displayMode: displayMode, throwOnError: false });
      return;
    }

    if (katex && typeof katex.renderToString === "function") {
      node.innerHTML = katex.renderToString(raw, { displayMode: displayMode, throwOnError: false });
    }
  }

  window.renderMathInElement = function (root) {
    if (!root || !root.querySelectorAll) {
      return;
    }

    var nodes = root.querySelectorAll(".math.math-inline, .math.math-display");
    for (var i = 0; i < nodes.length; i++) {
      renderNode(nodes[i]);
    }
  };
})();